import React from 'react';

const ServiceCard = ({ service }) => {
  const { name, type, address, distance, phone } = service;

  // Format type to look nice (e.g., first_aid -> First Aid)
  const formatType = (str) => {
    return str.split('_')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');
  };

  return (
    <div className="service-card">
      <div className="card-header">
        <span className="card-type">{formatType(type)}</span>
        <span className="card-distance">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path>
            <circle cx="12" cy="10" r="3"></circle>
          </svg>
          {distance.toFixed(1)} km
        </span>
      </div>

      <h3 className="card-title">{name}</h3>
      <p className="card-address">{address}</p>

      <div className="card-footer">
        {phone ? (
          <a href={`tel:${phone}`} className="card-phone">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"></path>
            </svg>
            {phone}
          </a>
        ) : (
          <span className="card-phone" style={{ color: '#9CA3AF', cursor: 'default' }}>
            No phone available
          </span>
        )}
      </div>
    </div>
  );
};

export default ServiceCard;
